const base = env.get('REST980_URL');
if (!base) { node.error('REST980_URL not set'); return null; }
msg.url = `${base}/api/local/info/state`;
return msg;

if (msg.statusCode >= 400) {
    msg.payload = JSON.stringify({ error: `HTTP ${msg.statusCode}` });
    return msg;
}
const d = msg.payload || {};
const m = d.cleanMissionStatus || {};
msg.payload = JSON.stringify({
    cycle:             m.cycle     || null,
    phase:             m.phase     || null,
    battery_pct:       d.batPct    !== undefined ? d.batPct   : null,
    cleaning_time_min: m.mssnM     !== undefined ? m.mssnM    : null,
    sqft:              m.sqft      !== undefined ? m.sqft     : null,
    error:             m.error     !== undefined ? m.error    : null,
    pmap_id:           (d.lastCommand && d.lastCommand.pmapId) || null,
    initiator:         m.initiator || null
});
return msg;

const VALID = ['start', 'stop', 'pause', 'dock', 'resume'];
const action = (msg.payload || {}).action;
if (!action || !VALID.includes(action)) {
    msg.payload = JSON.stringify({ error: `Invalid action '${action}'. Use: ${VALID.join(', ')}` });
    return [null, msg];
}
const base = env.get('REST980_URL');
if (!base) {
    msg.payload = JSON.stringify({ error: 'REST980_URL not set' });
    return [null, msg];
}
msg._action = action;
msg.url = `${base}/api/local/action/${action}`;
return [msg, null];

if (msg.statusCode >= 400) {
    msg.payload = JSON.stringify({ error: `HTTP ${msg.statusCode}` });
    return msg;
}
msg.payload = JSON.stringify({ action: msg._action, ok: true });
return msg;

const base = env.get('REST980_URL');
if (!base) { node.error('REST980_URL not set'); return null; }
const { pmap_id, region_ids, user_pmapv_id, ordered } = msg.payload || {};
msg.url = `${base}/api/local/action/cleanRoom`;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    ordered:  ordered === false ? 0 : 1,
    pmap_id,
    regions:  (region_ids || []).map(id => ({ region_id: String(id), type: 'rid' }))
};
if (user_pmapv_id) msg.payload.user_pmapv_id = user_pmapv_id;
return msg;

if (msg.statusCode >= 400) {
    msg.payload = JSON.stringify({ error: `HTTP ${msg.statusCode}` });
    return msg;
}
const raw = msg.payload || {};
msg.payload = JSON.stringify({ ok: raw.ok !== undefined ? !!raw.ok : msg.statusCode < 300 });
return msg;
